import React, { useState, useEffect, useCallback, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { InputText } from 'primereact/inputtext';
import { Button } from 'primereact/button';
import { Card } from 'primereact/card';
import { TabView, TabPanel } from 'primereact/tabview';
import { Tag } from 'primereact/tag';
import { Toast } from 'primereact/toast';
import { Dialog } from 'primereact/dialog';
import { ProgressBar } from 'primereact/progressbar';
import {
  createIndividualClient,
  createCorporateClient,
  getIndividualClients,
  getCorporateClients,
  getAccountsByClient,
  closeAccount,
  getLoansByClient,
  getRepaymentPlan,
  payInstalment,
} from '../api';
import {
  IndividualClient,
  CorporateClient,
  BankAccount,
  Loan,
  RepaymentInstalment,
} from '../types';
import './ClientsPage.css';

// ── Repayment Plan Dialog ────────────────────────────────────────────────────

const RepaymentPlanDialog: React.FC<{
  loanId: number | null;
  onHide: () => void;
  toast: React.RefObject<Toast>;
}> = ({ loanId, onHide, toast }) => {
  const [plan, setPlan] = useState<RepaymentInstalment[]>([]);
  const [loading, setLoading] = useState(false);
  const [payingMonth, setPayingMonth] = useState<number | null>(null);

  useEffect(() => {
    if (loanId === null) return;
    setLoading(true);
    getRepaymentPlan(loanId)
      .then(setPlan)
      .catch((e) => toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message }))
      .finally(() => setLoading(false));
  }, [loanId, toast]);

  const handlePay = async (inst: RepaymentInstalment) => {
    if (!loanId) return;
    setPayingMonth(inst.monthNumber);
    try {
      await payInstalment(loanId, inst.monthNumber);
      const updated = await getRepaymentPlan(loanId);
      setPlan(updated);
      toast.current?.show({ severity: 'success', summary: 'Paid', detail: `Month ${inst.monthNumber} marked as paid.` });
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setPayingMonth(null);
    }
  };

  const paid = plan.filter((i) => i.paid).length;
  const pct = plan.length > 0 ? Math.round((paid / plan.length) * 100) : 0;

  const statusBody = (row: RepaymentInstalment) =>
    row.paid
      ? <Tag severity="success" value="Paid" />
      : <Tag severity="warning" value="Unpaid" />;

  const actionBody = (row: RepaymentInstalment) =>
    row.paid ? null : (
      <Button
        label="Pay"
        icon="pi pi-check"
        size="small"
        loading={payingMonth === row.monthNumber}
        onClick={() => handlePay(row)}
      />
    );

  const rowClass = (row: RepaymentInstalment) => ({ 'cp-row-paid': row.paid });

  const fmtBGN = (val: number) => `BGN ${val.toFixed(2)}`;

  return (
    <Dialog
      header={`Repayment Plan — Loan #${loanId}`}
      visible={loanId !== null}
      onHide={onHide}
      style={{ width: '90vw', maxWidth: 900 }}
      modal
      dismissableMask
    >
      {loading ? (
        <ProgressBar mode="indeterminate" style={{ height: 4 }} />
      ) : (
        <>
          <div className="cp-plan-progress">
            <span>{paid} of {plan.length} instalments paid</span>
            <ProgressBar value={pct} style={{ height: 8, marginTop: 8 }} />
          </div>
          <DataTable
            value={plan}
            rowClassName={rowClass}
            stripedRows
            size="small"
            scrollable
            scrollHeight="420px"
          >
            <Column field="monthNumber" header="Month" style={{ width: 70 }} />
            <Column field="totalPayment" header="Total Payment" body={(r) => fmtBGN(r.totalPayment)} />
            <Column field="principalPart" header="Principal" body={(r) => fmtBGN(r.principalPart)} />
            <Column field="interestPart" header="Interest" body={(r) => fmtBGN(r.interestPart)} />
            <Column field="remainingBalance" header="Remaining" body={(r) => fmtBGN(r.remainingBalance)} />
            <Column header="Status" body={statusBody} style={{ width: 90 }} />
            <Column header="Action" body={actionBody} style={{ width: 90 }} />
          </DataTable>
        </>
      )}
    </Dialog>
  );
};

// ── Client Detail Panel (accounts + loans) ───────────────────────────────────

const ClientDetailPanel: React.FC<{
  clientId: number;
  toast: React.RefObject<Toast>;
}> = ({ clientId, toast }) => {
  const [accounts, setAccounts] = useState<BankAccount[]>([]);
  const [loans, setLoans] = useState<Loan[]>([]);
  const [loadingAcc, setLoadingAcc] = useState(true);
  const [loadingLoans, setLoadingLoans] = useState(true);
  const [closingId, setClosingId] = useState<number | null>(null);
  const [planLoanId, setPlanLoanId] = useState<number | null>(null);

  const loadAccounts = useCallback(async () => {
    setLoadingAcc(true);
    try {
      setAccounts(await getAccountsByClient(clientId));
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setLoadingAcc(false);
    }
  }, [clientId, toast]);

  const loadLoans = useCallback(async () => {
    setLoadingLoans(true);
    try {
      setLoans(await getLoansByClient(clientId));
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setLoadingLoans(false);
    }
  }, [clientId, toast]);

  useEffect(() => { loadAccounts(); loadLoans(); }, [loadAccounts, loadLoans]);

  const handleClose = async (acc: BankAccount) => {
    setClosingId(acc.id);
    try {
      await closeAccount(acc.id);
      await loadAccounts();
      toast.current?.show({ severity: 'success', summary: 'Closed', detail: `Account ${acc.iban} closed.` });
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setClosingId(null);
    }
  };

  const statusBody = (row: BankAccount) =>
    <Tag
      value={row.status}
      severity={row.status === 'ACTIVE' ? 'success' : 'danger'}
    />;

  const closeBody = (row: BankAccount) => (
    <Button
      label="Close"
      icon="pi pi-times"
      size="small"
      severity="danger"
      outlined
      disabled={row.status === 'CLOSED' || closingId === row.id}
      loading={closingId === row.id}
      onClick={() => handleClose(row)}
    />
  );

  const categoryBody = (row: Loan) => (
    <Tag
      value={row.loanCategory}
      severity={row.loanCategory === 'CONSUMER' ? 'info' : 'warning'}
    />
  );

  const progressBody = (row: Loan) => (
    <span>{row.paidInstalments}/{row.totalInstalments}</span>
  );

  const planBody = (row: Loan) => (
    <Button
      label="View Plan"
      icon="pi pi-list"
      size="small"
      text
      onClick={(e) => { e.stopPropagation(); setPlanLoanId(row.id); }}
    />
  );

  return (
    <div className="cp-detail-panel">
      <div className="cp-detail-section">
        <h4 className="cp-detail-heading"><i className="pi pi-credit-card" /> Bank Accounts</h4>
        <DataTable value={accounts} loading={loadingAcc} size="small" emptyMessage="No accounts." stripedRows>
          <Column field="iban" header="IBAN" />
          <Column field="balance" header="Balance" body={(r) => `BGN ${r.balance.toFixed(2)}`} />
          <Column header="Status" body={statusBody} style={{ width: 100 }} />
          <Column header="Action" body={closeBody} style={{ width: 110 }} />
        </DataTable>
      </div>

      <div className="cp-detail-section">
        <h4 className="cp-detail-heading"><i className="pi pi-dollar" /> Loans</h4>
        <DataTable value={loans} loading={loadingLoans} size="small" emptyMessage="No loans." stripedRows>
          <Column field="id" header="ID" style={{ width: 60 }} body={(r) => `#${r.id}`} />
          <Column header="Category" body={categoryBody} style={{ width: 110 }} />
          <Column field="amount" header="Amount" body={(r) => `BGN ${r.amount.toFixed(2)}`} />
          <Column field="termMonths" header="Term" body={(r) => `${r.termMonths} mo.`} style={{ width: 80 }} />
          <Column header="Progress" body={progressBody} style={{ width: 90 }} />
          <Column header="Plan" body={planBody} style={{ width: 110 }} />
        </DataTable>
      </div>

      <RepaymentPlanDialog
        loanId={planLoanId}
        onHide={() => setPlanLoanId(null)}
        toast={toast}
      />
    </div>
  );
};

// ── Individual Tab ───────────────────────────────────────────────────────────

const IndividualTab: React.FC<{ toast: React.RefObject<Toast> }> = ({ toast }) => {
  const [clients, setClients] = useState<IndividualClient[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [expandedRows, setExpandedRows] = useState<any>(null);
  const [form, setForm] = useState({ firstName: '', lastName: '', egn: '' });

  const load = useCallback(async () => {
    setLoading(true);
    try { setClients(await getIndividualClients()); }
    catch (e: any) { toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message }); }
    finally { setLoading(false); }
  }, [toast]);

  useEffect(() => { load(); }, [load]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.firstName.trim() || !form.lastName.trim() || !form.egn.trim()) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'All fields are required.' });
      return;
    }
    setSubmitting(true);
    try {
      await createIndividualClient(form);
      toast.current?.show({ severity: 'success', summary: 'Created', detail: 'Individual client registered.' });
      setForm({ firstName: '', lastName: '', egn: '' });
      await load();
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setSubmitting(false);
    }
  };

  const rowExpansionTemplate = (row: IndividualClient) => (
    <ClientDetailPanel clientId={row.id} toast={toast} />
  );

  return (
    <div>
      <Card className="cp-form-card" title="Register Individual Client">
        <form className="cp-form" onSubmit={handleSubmit}>
          <div className="cp-form-grid">
            <div className="cp-field">
              <label>First Name</label>
              <InputText
                value={form.firstName}
                onChange={(e) => setForm((f) => ({ ...f, firstName: e.target.value }))}
                placeholder="e.g. Ivan"
                disabled={submitting}
              />
            </div>
            <div className="cp-field">
              <label>Last Name</label>
              <InputText
                value={form.lastName}
                onChange={(e) => setForm((f) => ({ ...f, lastName: e.target.value }))}
                placeholder="e.g. Petrov"
                disabled={submitting}
              />
            </div>
            <div className="cp-field">
              <label>EGN</label>
              <InputText
                value={form.egn}
                onChange={(e) => setForm((f) => ({ ...f, egn: e.target.value }))}
                placeholder="10-digit EGN"
                disabled={submitting}
                maxLength={10}
              />
            </div>
          </div>
          <Button
            type="submit"
            label="Register Client"
            icon="pi pi-user-plus"
            loading={submitting}
            className="cp-submit-btn"
          />
        </form>
      </Card>

      <Card className="cp-table-card" title="Individual Clients">
        <DataTable
          value={clients}
          loading={loading}
          expandedRows={expandedRows}
          onRowToggle={(e) => setExpandedRows(e.data)}
          rowExpansionTemplate={rowExpansionTemplate}
          dataKey="id"
          stripedRows
          paginator
          rows={10}
          emptyMessage="No individual clients registered yet."
        >
          <Column expander style={{ width: 40 }} />
          <Column field="id" header="ID" style={{ width: 70 }} body={(r) => `#${r.id}`} sortable />
          <Column field="firstName" header="First Name" sortable />
          <Column field="lastName" header="Last Name" sortable />
          <Column field="egn" header="EGN" />
        </DataTable>
      </Card>
    </div>
  );
};

// ── Corporate Tab ────────────────────────────────────────────────────────────

const CorporateTab: React.FC<{ toast: React.RefObject<Toast> }> = ({ toast }) => {
  const [clients, setClients] = useState<CorporateClient[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [expandedRows, setExpandedRows] = useState<any>(null);
  const [form, setForm] = useState({
    companyName: '', eik: '', representativeFirstName: '', representativeLastName: '',
  });

  const load = useCallback(async () => {
    setLoading(true);
    try { setClients(await getCorporateClients()); }
    catch (e: any) { toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message }); }
    finally { setLoading(false); }
  }, [toast]);

  useEffect(() => { load(); }, [load]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.companyName.trim() || !form.eik.trim() || !form.representativeFirstName.trim() || !form.representativeLastName.trim()) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'All fields are required.' });
      return;
    }
    setSubmitting(true);
    try {
      await createCorporateClient(form);
      toast.current?.show({ severity: 'success', summary: 'Created', detail: 'Corporate client registered.' });
      setForm({ companyName: '', eik: '', representativeFirstName: '', representativeLastName: '' });
      await load();
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setSubmitting(false);
    }
  };

  const rowExpansionTemplate = (row: CorporateClient) => (
    <ClientDetailPanel clientId={row.id} toast={toast} />
  );

  return (
    <div>
      <Card className="cp-form-card" title="Register Corporate Client">
        <form className="cp-form" onSubmit={handleSubmit}>
          <div className="cp-form-grid">
            <div className="cp-field">
              <label>Company Name</label>
              <InputText
                value={form.companyName}
                onChange={(e) => setForm((f) => ({ ...f, companyName: e.target.value }))}
                placeholder="e.g. Acme Ltd."
                disabled={submitting}
              />
            </div>
            <div className="cp-field">
              <label>EIK</label>
              <InputText
                value={form.eik}
                onChange={(e) => setForm((f) => ({ ...f, eik: e.target.value }))}
                placeholder="Company EIK"
                disabled={submitting}
              />
            </div>
            <div className="cp-field">
              <label>Representative First Name</label>
              <InputText
                value={form.representativeFirstName}
                onChange={(e) => setForm((f) => ({ ...f, representativeFirstName: e.target.value }))}
                placeholder="e.g. Georgi"
                disabled={submitting}
              />
            </div>
            <div className="cp-field">
              <label>Representative Last Name</label>
              <InputText
                value={form.representativeLastName}
                onChange={(e) => setForm((f) => ({ ...f, representativeLastName: e.target.value }))}
                placeholder="e.g. Dimitrov"
                disabled={submitting}
              />
            </div>
          </div>
          <Button
            type="submit"
            label="Register Client"
            icon="pi pi-building"
            loading={submitting}
            className="cp-submit-btn"
          />
        </form>
      </Card>

      <Card className="cp-table-card" title="Corporate Clients">
        <DataTable
          value={clients}
          loading={loading}
          expandedRows={expandedRows}
          onRowToggle={(e) => setExpandedRows(e.data)}
          rowExpansionTemplate={rowExpansionTemplate}
          dataKey="id"
          stripedRows
          paginator
          rows={10}
          emptyMessage="No corporate clients registered yet."
        >
          <Column expander style={{ width: 40 }} />
          <Column field="id" header="ID" style={{ width: 70 }} body={(r) => `#${r.id}`} sortable />
          <Column field="companyName" header="Company" sortable />
          <Column field="eik" header="EIK" />
          <Column
            header="Representative"
            body={(r: CorporateClient) => `${r.representativeFirstName} ${r.representativeLastName}`}
          />
        </DataTable>
      </Card>
    </div>
  );
};

